// // Asynchronous reset and set capabilities: on the rising edge of the clock, if the reset signal is deasserted, the output q is cleared to LOW and qn is set to HIGH. If the set signal is deasserted, the output q is set to HIGH and qn is cleared to LOW. If neither reset nor set is active, the output q takes the value of the input d, while qn provides the complementary output.
module top_module(
    input wire clk,
    input wire rst,
    input wire set,
    input wire d,
    output reg q,
    output reg qn
);always @ (posedge clk) begin
    if (rst) begin
        q <= 0;
        qn <= 1;
    end else if (set) begin
        q <= 1;
        qn <= 0;
    end else begin
        q <= d;
        qn <= ~d;
    end
end

endmodule
